package com.carlib.api.animation; import java.util.Map;import java.util.Optional;import java.util.concurrent.ConcurrentHashMap;
public final class AnimationApi { private static final Map<String, EntityAnimationController> ENTITY_CONTROLLERS=new ConcurrentHashMap<>(); private static final Map<String, ItemAnimationController> ITEM_CONTROLLERS=new ConcurrentHashMap<>(); private AnimationApi(){} public static void registerEntityController(EntityAnimationController c){ENTITY_CONTROLLERS.put(c.providerId(),c);} public static void registerItemController(ItemAnimationController c){ITEM_CONTROLLERS.put(c.providerId(),c);} public static Optional<EntityAnimationController> entityController(String id){return Optional.ofNullable(ENTITY_CONTROLLERS.get(id));} public static Optional<ItemAnimationController> itemController(String id){return Optional.ofNullable(ITEM_CONTROLLERS.get(id));}}
